import { useEffect, useState } from 'react';
import { Plus, Pencil, Trash2, Package, Search } from 'lucide-react';
import { productService } from '../services/api';
import { Modal, FormField, ConfirmDialog, DataTable, EmptyState, PageLoader } from '../components/UI';
import toast from 'react-hot-toast';

// в”Ђв”Ђв”Ђ Product Form Modal в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
const ProductModal = ({ isOpen, onClose, onSaved, editProduct }) => {
  const isEdit = !!editProduct;
  const [form, setForm]       = useState({ name: '', description: '', price: '', stock: '' });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (editProduct) {
      setForm({
        name: editProduct.name,
        description: editProduct.description || '',
        price: editProduct.price,
        stock: editProduct.stock,
      });
    } else {
      setForm({ name: '', description: '', price: '', stock: '' });
    }
  }, [editProduct, isOpen]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const data = { ...form, price: parseFloat(form.price), stock: parseInt(form.stock) };
      if (isEdit) {
        await productService.update(editProduct.id, data);
        toast.success('Cбє­p nhбє­t sбєЈn phбє©m thГ nh cГґng!');
      } else {
        await productService.create(data);
        toast.success('TбєЎo sбєЈn phбє©m thГ nh cГґng!');
      }
      onSaved();
      onClose();
    } catch (err) {
      toast.error(err.response?.data?.message || 'CГі lб»—i xбєЈy ra!');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={isEdit ? 'Sб»­a sбєЈn phбє©m' : 'ThГЄm sбєЈn phбє©m mб»›i'}>
      <form onSubmit={handleSubmit} className="space-y-4">
        <FormField label="TГЄn sбєЈn phбє©m" required>
          <input className="input-field" placeholder="iPhone 15 Pro" value={form.name}
            onChange={e => setForm(f => ({ ...f, name: e.target.value }))} required />
        </FormField>
        <FormField label="MГґ tбєЈ">
          <textarea className="input-field resize-none h-20" placeholder="MГґ tбєЈ sбєЈn phбє©m..." value={form.description}
            onChange={e => setForm(f => ({ ...f, description: e.target.value }))} />
        </FormField>
        <div className="grid grid-cols-2 gap-4">
          <FormField label="GiГЎ (VNДђ)" required>
            <input type="number" min="0" className="input-field" placeholder="29000000" value={form.price}
              onChange={e => setForm(f => ({ ...f, price: e.target.value }))} required />
          </FormField>
          <FormField label="Tб»“n kho" required>
            <input type="number" min="0" className="input-field" placeholder="100" value={form.stock}
              onChange={e => setForm(f => ({ ...f, stock: e.target.value }))} required />
          </FormField>
        </div>
        <div className="flex gap-3 justify-end pt-2">
          <button type="button" onClick={onClose} className="btn-secondary">Hб»§y</button>
          <button type="submit" disabled={loading} className="btn-primary">
            {loading ? 'Дђang lЖ°u...' : isEdit ? 'Cбє­p nhбє­t' : 'TбєЎo mб»›i'}
          </button>
        </div>
      </form>
    </Modal>
  );
};

